// entry point — triggers the initial render
import { createRoot } from 'react-dom/client';
import App from './App';

const root = createRoot(document.getElementById('root'));
root.render(<App />);
// Every component in the <App /> tree runs now for the first time.

function Counter() {
  const [count, setCount] = useState(0);
  // First render: count = 0, DOM shows "0"
  // After click: React re-renders Counter, count = 1, patches text node to "1"
  return (
    <button onClick={() => setCount(c => c + 1)}>
      {count}
    </button>
  );
}

function Example() {
  const [count, setCount] = useState(0);

  function noRerender() {
    // None of these cause a re-render:
    count;                    // reading state is fine
    setCount(0);              // same value — React bails out
    someRef.current = 42;    // ref mutation — bypasses React
    someLocalVar = 'changed'; // JS mutation — React can't see it
  }

  function causesRerender() {
    setCount(1); // new value → triggers re-render
  }
}

function Counter() {
  // On re-render, React restores count from its internal store.
  // Calling useState here does NOT reinitialize to 0.
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Rendered {/* count times */}</p>
      <button onClick={() => setCount(c => c + 1)}>+</button>
    </div>
  );
}
// The 0 passed to useState is only used on the FIRST render.

function App() {
  const [show, setShow] = useState(true);
  return (
    <>
      {show && <Counter />} {/* unmounts when show=false → state lost */}
      <button onClick={() => setShow(s => !s)}>Toggle</button>
    </>
  );
}
// When show flips false → Counter unmounts, count destroyed.
// When show flips true again → Counter mounts, count starts at 0 again.

function Parent({ isAdmin }) {
  // Position 0 in Parent's JSX output is always a Counter-like component
  // BUT: type switches between AdminCounter and Counter
  return isAdmin ? <AdminCounter /> : <Counter />;
  // When isAdmin flips: old component unmounts (state lost),
  // new component mounts (state initialized fresh).
  // React cannot tell they are "the same" — different types.
}

function Parent() {
  const [x, setX] = useState(0);
  // When x changes, BOTH children re-render by default:
  return (
    <>
      <ExpensiveList />   {/* re-renders even though it gets no props */}
      <p>{x}</p>
    </>
  );
}

// Wrap with memo to opt out:
const ExpensiveList = React.memo(function ExpensiveList() {
  return <ul>{/* long list */}</ul>;
});
// Now ExpensiveList only re-renders if its own props change.

// GrandParent doesn't re-render → its JSX is stable
function GrandParent() {
  return (
    <Counter>
      <ExpensiveList />
    </Counter>
  );
}

function Counter({ children }) {
  const [count, setCount] = useState(0);
  // Counter re-renders on click, but children (ExpensiveList) was
  // created by GrandParent, which didn't re-render — so it won't re-render.
  return (
    <div>
      <button onClick={() => setCount(c => c + 1)}>{count}</button>
      {children}
    </div>
  );
}

function Timer({ delay }) {
  useEffect(() => {
    // INITIAL MOUNT: runs after first paint. No cleanup before this.
    // RE-RENDER (delay changed): cleanup of previous timer, then new setup.
    // UNMOUNT: cleanup of last timer, setup never called again.
    const id = setInterval(() => tick(), delay);
    return () => clearInterval(id); // cleanup
  }, [delay]);
}

function ProfilePage({ userId }) {
  // Changing userId changes the key => Profile unmounts and remounts
  // All state inside Profile resets as if it were a fresh initial render
  return <Profile key={userId} userId={userId} />;
}

function Profile({ userId }) {
  const [tab, setTab] = useState("posts");
  // tab resets to "posts" every time userId changes
  return (
    <div>
      <button onClick={() => setTab("posts")}>Posts</button>
      <button onClick={() => setTab("bio")}>Bio</button>
    </div>
  );
}

const [items, setItems] = useState([1, 2, 3]);

// Same array reference -> skipped
setItems(items);

// New array reference -> WILL re-render
setItems([1, 2, 3]);

// Primitive: same value -> skipped
const [count, setCount] = useState(0);
setCount(0); // skipped
setCount(1); // scheduled

function FilteredList({ items }) {
  const [query, setQuery] = useState("");
  const deferredQuery = useDeferredValue(query); // low-priority copy

  // query updates urgently on every keystroke
  // deferredQuery lags behind -> expensive filter runs at lower priority
  const filtered = items.filter(i => i.name.includes(deferredQuery));

  return (
    <>
      <input value={query} onChange={e => setQuery(e.target.value)} />
      {filtered.map(i => <Row key={i.id} item={i} />)}
    </>
  );
}

function Label({ value }) {
  // Re-renders whenever parent does, but if value is the same,
  // React skips the DOM update for this text node.
  return <span>{value}</span>;
}

// To avoid even the function call:
const Label = React.memo(function Label({ value }) {
  return <span>{value}</span>;
});
// Now Label only re-renders when the value prop changes.

import { render, screen, rerender } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

test('counter increments on click', async () => {
  render(<Counter />);
  expect(screen.getByText('0')).toBeInTheDocument();

  await userEvent.click(screen.getByRole('button'));
  expect(screen.getByText('1')).toBeInTheDocument();
});

test('resets when key changes', () => {
  const { rerender } = render(<Counter key='a' />);
  // Changing the key forces a remount and state reset
  rerender(<Counter key='b' />);
  expect(screen.getByText('0')).toBeInTheDocument();
});
